import './App.css';
import Navbar from './componentes/navbar';
import Footer from './componentes/footer';
import Abogadas from './componentes/abogadas';
function App() {
  return (
    <div className="App">
    <header className="header">
      <Navbar />
    </header>
      <body>
        <h1>Bienvenidos a YGU Abogada y notariada publica</h1>
        <Abogadas 
         nombre={"Maria"}
          imagen={"https://www.abogados.com.co/wp-content/uploads/2020/11/abogada-1.jpg"}
          especialidades={["Derecho Civil", "Derecho Penal", "Derecho Laboral"]}
        />
      </body>

      <footer>
        <Footer />
      </footer>

    </div>
  );
}

export default App;
